const ImpactBurst: React.FC<{
  frame: number;
  energy: number;
  opacity: number;
}> = ({ frame, energy, opacity }) => {
  const centerX = 420;
  const centerY = 300;
  return (
    <>
      <svg
        width="840"
        height="600"
        viewBox="0 0 840 600"
        style={{ position: "absolute", inset: 0, overflow: "visible", opacity }}
      >
        {[0, 1, 2].map((index) => (
          <ellipse
            key={index}
            cx={centerX}
            cy={centerY}
            rx={(48 + index * 34) * (0.7 + energy * 2.4)}
            ry={(20 + index * 14) * (0.7 + energy * 2.4)}
            fill="none"
            stroke={index === 1 ? "#FFF0A5" : "#F7B934"}
            strokeWidth={4 - index}
            opacity={(1 - energy) * (0.78 - index * 0.16)}
          />
        ))}
      </svg>
      {Array.from({ length: 24 }).map((_, index) => {
        const angle = seeded(index, 23) * Math.PI * 2;
        const radius = energy * (90 + seeded(index, 24) * 330);
        const x = centerX + Math.cos(angle) * radius;
        const y = centerY + Math.sin(angle) * radius * 0.54;
        const size = 3 + seeded(index, 25) * 7;
        return (
          <div
            key={index}
            style={{
              position: "absolute",
              left: x - size / 2,
              top: y - size / 2,
              width: size,
              height: size * (index % 5 === 0 ? 3 : 1),
              borderRadius: size,
              background: index % 3 === 0 ? "#54F1DC" : "#FFD15B",
              boxShadow: `0 0 ${size * 3}px ${index % 3 === 0 ? "#54F1DC" : "#FFB32C"}`,
              opacity: opacity * (1 - energy) * 0.95,
              transform: `rotate(${(angle * 180) / Math.PI + 90}deg)`,
            }}
          />
        );
      })}
    </>
  );
};

