type DepositTiming = {
  start: number;
  lift: number;
  fall: number;
  impact: number;
  startX: number;
};

const DEPOSITS: DepositTiming[] = [
  { start: 150, lift: 180, fall: 192, impact: 228, startX: 285 },
  { start: 246, lift: 270, fall: 282, impact: 318, startX: 548 },
  { start: 336, lift: 358, fall: 370, impact: 404, startX: 318 },
  { start: 422, lift: 444, fall: 456, impact: 488, startX: 536 },
  { start: 506, lift: 528, fall: 540, impact: 570, startX: 420 },
];

const COIN_VALUE = 20;
const WALLET_IMAGE_LEFT = 40;
const WALLET_IMAGE_TOP = 15;
const WALLET_IMAGE_WIDTH = 760;
const SLOT_X = 420;
const SLOT_Y = 305;

const impactPulseAt = (frame: number, impact: number, duration = 42) => {
  if (frame < impact || frame > impact + duration) return 0;
  const progress = (frame - impact) / duration;
  return Math.sin(progress * Math.PI) * Math.exp(-progress * 0.7);
};

