const DepositCoin: React.FC<{
  frame: number;
  fps: number;
  timing: DepositTiming;
  index: number;
}> = ({ frame, fps, timing, index }) => {
  const appear = clamp01(
    spring({
      frame: frame - timing.start,
      fps,
      config: { mass: 0.65, damping: 12, stiffness: 155 },
    }),
  );
  const lift = phase(frame, timing.lift, timing.fall, Easing.out(Easing.cubic));
  const drop = phase(
    frame,
    timing.fall,
    timing.impact,
    Easing.in(Easing.cubic),
  );
  const sink = phase(
    frame,
    timing.impact,
    timing.impact + 25,
    Easing.in(Easing.quad),
  );
  const vanish = phase(
    frame,
    timing.impact + 16,
    timing.impact + 37,
    Easing.in(Easing.quad),
  );
  const hoverY =
    -55 + Math.sin((frame - timing.start) * 0.08 + index * 0.8) * 7;
  const liftedY = hoverY - lift * 27;
  const startFallY =
    -55 + Math.sin((timing.fall - timing.start) * 0.08 + index * 0.8) * 7 - 27;
  const y =
    (drop > 0 ? interpolate(drop, [0, 1], [startFallY, SLOT_Y]) : liftedY) +
    sink * 112;
  const x =
    interpolate(drop, [0, 1], [timing.startX, SLOT_X]) +
    Math.sin((frame - timing.start) * 0.045 + index) * 8 * (1 - drop);
  const flip =
    0.28 +
    Math.abs(Math.cos((frame - timing.start) * 0.1 + index * 0.4)) * 0.72;
  const opacity = appear * (1 - vanish);
  const size = 145 * (0.82 + appear * 0.18);

  return (
    <>
      {drop > 0 && drop < 1 && (
        <MoneyCoin
          id={`deposit-trail-${index}`}
          x={interpolate(
            Math.max(0, drop - 0.1),
            [0, 1],
            [timing.startX, SLOT_X],
          )}
          y={interpolate(Math.max(0, drop - 0.1), [0, 1], [startFallY, SLOT_Y])}
          size={size * 0.9}
          opacity={opacity * 0.12}
          rotation={(frame - timing.start) * (1.5 + index * 0.1)}
          flip={flip}
          blur={7}
          glow={0.7}
        />
      )}
      <MoneyCoin
        id={`deposit-${index}`}
        x={x}
        y={y}
        size={size}
        opacity={opacity}
        rotation={(frame - timing.start) * (1.22 + index * 0.08) + drop * 105}
        flip={flip}
        glow={1.05 + impactPulseAt(frame, timing.impact) * 1.35}
      />
    </>
  );
};

